select round(sum(a.total_number), 2) totalTotalNumber, round(sum(buyc.total_amount), 2) totalBtotalAmount, round(sum(a.total_amount), 2) totalStotalAmount, round(sum(b.gross_profit), 2) totalMarginAmount, round(sum(b.company_commission)) totalCompanyCommissionAmount, round(sum(b.company_commission) / sum(buy.total_amount), 4) aveCompanyCommissionRate, round(sum(a.dealed_amount), 2) totalSdealedAmount, round(sum(buyc.dealed_amount), 2) totalBdealedAmount, round(sum(a.billed_amount), 2) totalSbilledAmount, round(sum(buyc.dealed_amount), 2) totalBbilledAmount, round(sum(buyc.total_amount - buyc.dealed_amount), 2) totalBalancePayable, round(sum(a.total_amount - a.dealed_amount), 2) totalBalanceReceivable from t_ctr_contract a left join t_pm_approve c on c.id = a.approve_id left join t_apply_match b on b.approve_id = a.approve_id left join t_apply_match_detail buy on buy.apply_match_id = b.id left join t_ctr_contract buyc on buyc.id = buy.contract_id left join t_apply_match_detail sell on sell.apply_match_id = b.id where a.status = 'D' and a.contract_type = 'S' and buy.contract_type = 'B' and sell.contract_type = 'S'
and c.id in
#{item}

select a.approveId from ( ( select distinct c.id approveId from t_ctr_contract a left join t_pm_approve c on c.id = a.approve_id left join t_apply_match b on b.approve_id = a.approve_id left join t_apply_match_detail buy on buy.apply_match_id = b.id left join t_ctr_contract buyc on buyc.id = buy.contract_id left join t_apply_match_detail sell on sell.apply_match_id = b.id LEFT JOIN t_ctr_dcsx dc ON dc.approve_id = a.approve_id
a.status = 'D' and a.contract_type = 'S' and buy.contract_type = 'B' and sell.contract_type = 'S'
) a inner join ( select distinct c.id approveId from t_ctr_contract a left join t_pm_approve c on c.id = a.approve_id left join t_apply_match b on b.approve_id = a.approve_id left join t_apply_match_detail buy on buy.apply_match_id = b.id left join t_ctr_contract buyc on buyc.id = buy.contract_id left join t_apply_match_detail sell on sell.apply_match_id = b.id left join t_ctr_contract sell_c on sell_c.id = sell.contract_id LEFT JOIN t_ctr_dcsx dc ON dc.approve_id = a.approve_id
a.contract_type = 'B' and buy.contract_type = 'B' and sell.contract_type = 'S'
) b on a.approveId = b.approveId) order by a.approveId desc

select round(sum(a.total_number), 2) totalTotalNumber, round(sum(dc.total_amount), 2) totalBtotalAmount, round(sum(a.total_amount), 2) totalStotalAmount, round(sum(b.gross_profit), 2) totalMarginAmount, round(sum(b.company_commission)) totalCompanyCommissionAmount, round(sum(b.company_commission) / sum(buy.total_amount), 4) aveCompanyCommissionRate, round(sum(a.dealed_amount), 2) totalSdealedAmount, round(sum(dc.dealed_amount), 2) totalBdealedAmount, round(sum(a.billed_amount), 2) totalSbilledAmount, round(sum(dc.dealed_amount), 2) totalBbilledAmount, round(sum(dc.total_amount - dc.dealed_amount), 2) totalBalancePayable, round(sum(a.total_amount - a.dealed_amount), 2) totalBalanceReceivable from t_ctr_contract a left join t_pm_approve c on c.id = a.approve_id left join t_apply_match b on b.approve_id = a.approve_id left join t_apply_match_detail buy on buy.apply_match_id = b.id left join t_ctr_contract buyc on buyc.id = buy.contract_id left join t_apply_match_detail sell on sell.apply_match_id = b.id left join t_ctr_dcsx dc on dc.approve_id = a.approve_id where a.status = 'D' and dc.business_type = 'ZY-BB' and a.contract_type = 'S' and buy.contract_type = 'B' and sell.contract_type = 'S'
and c.id in
#{item}

